package org.eclipse.rdf4j.query.algebra.equivalence;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertNotSame;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.concurrent.atomic.AtomicReference;

import org.eclipse.rdf4j.common.annotation.Experimental;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.junit.jupiter.api.Test;

class PublicApiContractTest {

	@Test
	void publicPackageIsExperimental() {
		assertNotNull(AlgebraEquivalenceChecker.class.getPackage().getAnnotation(Experimental.class));
	}

	@Test
	void targetsNameRuntimeAndDraftSemanticsExplicitly() {
		assertTrue(SemanticsTarget.RDF4J_RUNTIME.isRuntimeTarget());
		assertTrue(SemanticsTarget.SPARQL_1_2_DRAFT.permitsSparql12Nodes());
	}

	@Test
	void functionPolicyNamesTheFullRelocationAndDuplicationContract() {
		FunctionSafetyPolicy policy = (uri, function) -> "urn:test:safe".equals(uri);
		CheckOptions options = CheckOptions.builder().functionSafetyPolicy(policy).build();

		assertEquals(policy, options.getFunctionSafetyPolicy());
		assertTrue(policy.isSafeForRelocationAndDuplication("urn:test:safe", null));
	}

	@Test
	void rewriteEngineInvokesRewritesOnDetachedClones() {
		TupleExpr original = new SingletonSet();
		AtomicReference<TupleExpr> rewriteInput = new AtomicReference<>();
		AlgebraRewrite rewrite = input -> {
			rewriteInput.set(input);
			return new Join(input, new SingletonSet());
		};

		VerifiedRewrite result = new VerifiedRewriteEngine(new AlgebraEquivalenceChecker()).apply(original, rewrite);

		assertTrue(result.accepted(), () -> result.result().getReason());
		assertNotSame(original, rewriteInput.get());
		assertEquals(new SingletonSet(), original);
	}
}
